import kotlinx.coroutines.testing.*
import kotlinx.coroutines.*
import kotlin.coroutines.*
import kotlin.test.*

/**
 * Test for handling dispatcher exceptions in flowOn.
 * This test verifies that when a dispatcher throws an exception,
 * the flow collection properly propagates the exception instead of hanging.
 * 
 * Related to: https://github.com/JetBrains/compose-multiplatform/issues/4835
 */
class FlowOnDispatcherExceptionTest : TestBase() {

    /**
     * A dispatcher that throws an exception when isDispatchNeeded is called.
     * This simulates the behavior of Dispatchers.Main.immediate when the Main dispatcher
     * is not available in the classpath.
     */
    private class FailingDispatcher(
        private val exceptionMessage: String = "Test dispatcher exception"
    ) : CoroutineDispatcher() {
        override fun dispatch(context: CoroutineContext, block: Runnable) {
            throw IllegalStateException(exceptionMessage)
        }

        override fun isDispatchNeeded(context: CoroutineContext): Boolean {
            throw IllegalStateException(exceptionMessage)
        }
    }

    @Test
    fun testFlowOnWithFailingDispatcher() = runTest {
        val failingDispatcher = FailingDispatcher("Dispatcher not available")

        val exception = assertFailsWith<IllegalStateException> {
            flowOf(1, 2, 3)
                .flowOn(failingDispatcher)
                .collect {
                    println("collect: $it")
                }
        }

        assertEquals("Dispatcher not available", exception.message)
    }

    @Test
    fun testFlowOnWithFailingDispatcherInChain() = runTest {
        val failingDispatcher = FailingDispatcher("Dispatcher not available")

        val exception = assertFailsWith<IllegalStateException> {
            flowOf(1, 2, 3)
                .map { it * 2 }
                .flowOn(failingDispatcher)
                .map { it + 1 }
                .collect {
                    println("collect: $it")
                }
        }

        assertEquals("Dispatcher not available", exception.message)
    }

    @Test
    fun testFlowOnWithFailingDispatcherAndBuffer() = runTest {
        val failingDispatcher = FailingDispatcher("Dispatcher not available")

        val exception = assertFailsWith<IllegalStateException> {
            flowOf(1, 2, 3)
                .buffer()
                .flowOn(failingDispatcher)
                .collect {
                    println("collect: $it")
                }
        }

        assertEquals("Dispatcher not available", exception.message)
    }

    @Test
    fun testMultipleFlowOnWithFailingDispatcher() = runTest {
        val failingDispatcher = FailingDispatcher("Dispatcher not available")

        val exception = assertFailsWith<IllegalStateException> {
            flowOf(1, 2, 3)
                .flowOn(Dispatchers.Default)  // This works
                .map { it * 2 }
                .flowOn(failingDispatcher)  // This fails
                .collect {
                    println("collect: $it")
                }
        }

        assertEquals("Dispatcher not available", exception.message)
    }

    @Test
    fun testFlowOnWithDispatchException() = runTest {
        // Test that the dispatcher exception is properly unwrapped
        val failingDispatcher = FailingDispatcher("Test exception")

        try {
            flowOf(1, 2, 3)
                .flowOn(failingDispatcher)
                .collect()
            fail("Expected exception")
        } catch (e: Exception) {
            // The exception should be the original exception, not wrapped in DispatchException
            assertTrue(e is IllegalStateException)
            assertEquals("Test exception", e.message)
        }
    }
}
"}

