140→public suspend fun <T> withContext(
141→    context: CoroutineContext,
142→    block: suspend CoroutineScope.() -> T
143→): T {
144→    contract {
145→        callsInPlace(block, InvocationKind.EXACTLY_ONCE)
146→    }
147→    return suspendCoroutineUninterceptedOrReturn sc@ { uCont ->
148→        // compute new context
149→        val oldContext = uCont.context
150→        // Copy CopyableThreadContextElement if necessary
151→        val newContext = oldContext.newCoroutineContext(context)
152→        // always check for cancellation of new context
153→        newContext.ensureActive()
154→        // FAST PATH #1 -- new context is the same as the old one
155→        if (newContext === oldContext) {
156→            val coroutine = ScopeCoroutine(newContext, uCont)
157→            return@sc coroutine.startUndispatchedOrReturn(coroutine, block)
158→        }
159→        // FAST PATH #2 -- the new dispatcher is the same as the old one (something else changed)
160→        // `equals` is used by design (see equals implementation is wrapper context like ExecutorCoroutineDispatcher)
161→        if (newContext[ContinuationInterceptor] == oldContext[ContinuationInterceptor]) {
162→            val coroutine = UndispatchedCoroutine(newContext, uCont)
163→            // There are changes in the context, so this thread needs to be updated
164→            withCoroutineContext(coroutine.context, null) {
165→                return@sc coroutine.startUndispatchedOrReturn(coroutine, block)
166→            }
167→        }
168→        // SLOW PATH -- use new dispatcher
169→        val coroutine = DispatchedCoroutine(newContext, uCont)
170→        block.startCoroutineCancellable(coroutine, coroutine)
171→        coroutine.getResult()
172→    }
173→}
