 23→        private val exceptionMessage: String = "Test dispatcher exception"
 24→    ) : CoroutineDispatcher() {
 25→        override fun dispatch(context: CoroutineContext, block: Runnable) {
 26→            throw IllegalStateException(exceptionMessage)
