 28→
 29→        override fun isDispatchNeeded(context: CoroutineContext): Boolean {
 30→            throw IllegalStateException(exceptionMessage)
 31→        }
 32→    }
 33→
 34→    @Test
 35→    fun testFlowOnWithFailingDispatcher() = runTest {
 36→        val failingDispatcher = FailingDispatcher("Dispatcher not available")
 37→        
 38→        val exception = assertFailsWith<IllegalStateException> {
 39→            flowOf(1, 2, 3)
 40→                .flowOn(failingDispatcher)
 41→                .collect {
 42→                    println("collect: $it")
 43→                }
 44→        }
 45→        
 46→        assertEquals("Dispatcher not available", exception.message)
 47→    }
