 50→    fun testFlowOnWithFailingDispatcherInChain() = runTest {
 51→        val failingDispatcher = FailingDispatcher("Dispatcher not available")
 52→        
 53→        val exception = assertFailsWith<IllegalStateException> {
 54→            flowOf(1, 2, 3)
